import{_ as o,U as l,n as d,p as c,v as u,a8 as n,q as t,L as a,E as s,C as r}from"./framework-520e1760.js";const p="/images/eportal-overview.svg",h="/images/eportal-cache-mode.svg",m="/images/eportal-with-proxy.svg",v="/images/eportalLDAPusers.png",g="/images/access_eportal.png",b="/images/eportal-edit-patch-source.png",f="/images/eportal-dashboard.png",x="/images/eportal-manage.png",y="/images/eportal-libcare-feed.png",k="/images/eportal-qemu-feed.png",w="/images/key-menu_zoom70.png",P="/images/eportal_keys_edit.png",_="/images/eportal_keys_remove.png",E="/images/key-creation_zoom70.png",T="/images/server_list_1_zoom70.png",A="/images/eportal-servers.png",R="/images/tags_view.png",S="/images/tag_assignment.png",C="/images/addingextratagfield_zoom88.png",L="/images/feed-button_zoom70.png",I="/images/feed-menu_zoom70.png",O="/images/feedmanagement3_zoom70.png",D="/images/feedmanagement4_zoom70.png",q="/images/feedmanagement5_01_zoom70.png",U="/images/api_key_list.png",N="/images/api_key_create.png",F="/images/api_key_generated.png",K="/images/overview_uptime_distribution.png",H="/images/overview_arch_distribution.png",Y="/images/overview_os_distribution.png",M="/images/overview_kernel_distribution.png",B="/images/sso_eportal.png",$={};function z(G,e){const i=l("RouterLink");return d(),c("div",null,[u(" markdownlint-disable MD014 MD033 MD029 MD049 MD034 MD051"),e[26]||(e[26]=n('<h1 id="eportal" tabindex="-1"><a class="header-anchor" href="#eportal" aria-hidden="true">#</a> ePortal</h1><p>TuxCare ePortal is the web management console dedicated to KernelCare Enterprise live patch management.</p><p>ePortal software can help protect servers located behind the firewall (i.e. with no internet access) and can be installed both on-premises and in the cloud.</p><p><img src="'+p+`" alt="Overview"></p><h2 id="eportal-hardware-requirements" tabindex="-1"><a class="header-anchor" href="#eportal-hardware-requirements" aria-hidden="true">#</a> ePortal Hardware Requirements</h2><p><strong>Disk:</strong></p><table><thead><tr><th>Installation mode</th><th>Minimum</th><th>Recommended</th></tr></thead><tbody><tr><td>Default (mirror all distros)</td><td>1 TB</td><td>2 TB</td></tr><tr><td>With distro filter</td><td>Scales with the subset of mirrored distros</td><td>—</td></tr><tr><td><a href="#cache-mode">Cache mode</a></td><td>25 GB</td><td>50 GB</td></tr></tbody></table><ul><li>SSD with at least 100 IOPS</li><li>Plan for additional growth of about 4–5 GiB/month</li></ul><div class="tip custom-block"><p class="custom-block-title">Note</p><p>SSD-based storage is a crucial requirement for ePortal server.</p></div><div class="tip custom-block"><p class="custom-block-title">Reducing disk usage</p><p>If full mirroring is not required, the footprint can be reduced significantly by:</p><ul><li>Enabling <a href="#cache-mode">cache mode</a> during installation — patchsets are served on demand from TuxCare instead of stored locally.</li><li>Limiting the set of mirrored distros via the <strong>Patch Source</strong> configuration — only the selected distros are downloaded.</li><li>Running <code>kc.eportal --clean-releases</code> regularly to purge obsolete patchsets. See <a href="#clean-obsolete-releases">Clean obsolete releases</a>.</li></ul></div><p><strong>CPU:</strong></p><p>As far as other requirements concerned, we have tested the following configuration and the following number of connected servers:</p><ul><li><p>10k of connected machines is the maximum for the following requirements:</p><ul><li>VM</li><li>1 VCPU</li><li>1 GB RAM</li></ul></li><li><p>75k of connected machines is the maximum for the following requirements:</p><ul><li>Core i5</li><li>1 CPU</li><li>4 GB RAM</li></ul></li></ul><h2 id="installation" tabindex="-1"><a class="header-anchor" href="#installation" aria-hidden="true">#</a> Installation</h2><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you are installing for the first time, please confirm with our sales engineering team at <a href="sales@tuxcare.com">sales@tuxcare.com</a> <strong>BEFORE</strong> trying the installation via the documentation below. Please note that support tickets resulting from not following this recommendation will not be accepted.</p></div><p>ePortal is compatible with 64-bit versions of EL7/8/9 based distros like CentOS 7/8, AlmaLinux 8/9/10, Ubuntu 20.04/22.04/24.04 and Debian 11/12/13</p><h2 id="automated-installation-script" tabindex="-1"><a class="header-anchor" href="#automated-installation-script" aria-hidden="true">#</a> Automated Installation Script</h2><p>TuxCare provides an automated installation script that simplifies the ePortal installation and configuration process. The script handles repository setup, package installation, and initial configuration.</p><h3 id="supported-distributions" tabindex="-1"><a class="header-anchor" href="#supported-distributions" aria-hidden="true">#</a> Supported Distributions</h3><p>The installer script supports the following distributions:</p><p><strong>RHEL-based:</strong></p><ul><li>AlmaLinux 8, 9, 10</li><li>Red Hat Enterprise Linux (RHEL) 8, 9, 10</li><li>Oracle Linux (OEL) 8, 9, 10</li></ul><p><strong>Debian-based:</strong></p><ul><li>Debian 11, 12, 13</li><li>Ubuntu 20.04, 22.04, 24.04</li></ul><h3 id="main-features" tabindex="-1"><a class="header-anchor" href="#main-features" aria-hidden="true">#</a> Main Features</h3><p>The installer script automates the following:</p><ul><li><strong>Repository Configuration</strong>: Automatically configures the required repositories (Nginx and TuxCare ePortal)</li><li><strong>Package Installation</strong>: Installs ePortal and all required dependencies</li><li><strong>Service Validation</strong>: Verifies that ePortal service is properly installed and running</li><li><strong>Admin Password Setup</strong>: Interactive configuration of the admin user password</li><li><strong>Cache Mode Configuration</strong>: Optional configuration to enable patch caching mode (reduces disk space requirements)</li><li><strong>Business Units Configuration</strong>: Optional setup for multi-tenant business unit isolation</li><li><strong>Proxy Configuration</strong>: Optional proxy server configuration for environments requiring it</li><li><strong>SSL Certificate Setup</strong>: Optional Let&#39;s Encrypt SSL certificate installation and configuration</li><li><strong>Firewall Configuration</strong>: Automatically configures firewall rules for HTTP/HTTPS access</li></ul><h3 id="using-the-installation-script" tabindex="-1"><a class="header-anchor" href="#using-the-installation-script" aria-hidden="true">#</a> Using the Installation Script</h3><p>Download and run the installer script:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl -O https://repo.cloudlinux.com/kcare-eportal/eportal_installer.sh
# chmod +x eportal_installer.sh
# ./eportal_installer.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The script will:</p><ol><li>Detect your Linux distribution and version</li><li>Configure the necessary repositories</li><li>Install ePortal and dependencies</li><li>Guide you through interactive configuration steps</li><li>Optionally configure SSL certificates</li></ol><p>After installation, you can access ePortal at <code>http://YOUR_SERVER_IP/admin</code> using the admin credentials you configured during installation.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>The installer script requires root privileges and will prompt you to agree to the terms before proceeding.</p></div><h2 id="manual-installation" tabindex="-1"><a class="header-anchor" href="#manual-installation" aria-hidden="true">#</a> Manual Installation</h2><p>If you prefer to install ePortal manually or need more control over the installation process, follow the instructions below.</p><h3 id="rhel-based-distros" tabindex="-1"><a class="header-anchor" href="#rhel-based-distros" aria-hidden="true">#</a> RHEL-based distros</h3><p>For installation and workability of ePortal the Nginx web server is required. We recommend to use stable version from the official Nginx repository:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># cat &gt; /etc/yum.repos.d/nginx.repo &lt;&lt;EOL
[nginx]
name=nginx stable repo
baseurl=http://nginx.org/packages/centos/\\$releasever/\\$basearch/
gpgcheck=1
enabled=1
gpgkey=https://nginx.org/keys/nginx_signing.key
module_hotfixes=true
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>You can find more information at <a href="https://nginx.org/en/linux_packages.html#stable" target="_blank" rel="noopener noreferrer">https://nginx.org/en/linux_packages.html#stable</a></p><p>Setup ePortal repo:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># cat &gt; /etc/yum.repos.d/kcare-eportal.repo &lt;&lt;EOL
[kcare-eportal]
name=KernelCare ePortal
baseurl=https://www.repo.cloudlinux.com/kcare-eportal/\\$releasever/\\$basearch/
enabled=1
gpgkey=https://repo.cloudlinux.com/kernelcare/RPM-GPG-KEY-KernelCare-rsa4096
gpgcheck=1
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you are using CentOS7, starting from ePortal version 2.4-2, it&#39;s necessary to install the <code>centos-release-scl</code> package. You can do so with the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># yum install centos-release-scl
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>For RHEL7 users, you&#39;ll need to enable the necessary repositories to ensure access to the required packages. Use the subscription-manager utility with the following commands:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># subscription-manager repos --enable rhel-7-server-optional-rpms
# subscription-manager repos --enable rhel-server-rhscl-7-rpms
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>For Oracle Linux 7 users, similar to CentOS7, you need to install the oracle-softwarecollection-release-el7 package. This can be done using the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># yum install oracle-softwarecollection-release-el7
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># yum install -y kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="ubuntu-2004" tabindex="-1"><a class="header-anchor" href="#ubuntu-2004" aria-hidden="true">#</a> Ubuntu 20.04</h3><p>Setup ePortal repo:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/20.04 focal main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="ubuntu-2204" tabindex="-1"><a class="header-anchor" href="#ubuntu-2204" aria-hidden="true">#</a> Ubuntu 22.04</h3><p>Setup ePortal repo:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/22.04 jammy main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="ubuntu-2404" tabindex="-1"><a class="header-anchor" href="#ubuntu-2404" aria-hidden="true">#</a> Ubuntu 24.04</h3><p>Setup ePortal repo:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/24.04 noble main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="debian-11" tabindex="-1"><a class="header-anchor" href="#debian-11" aria-hidden="true">#</a> Debian 11</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/debian/11 kcare main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="debian-12" tabindex="-1"><a class="header-anchor" href="#debian-12" aria-hidden="true">#</a> Debian 12</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/debian/12 kcare main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="debian-13" tabindex="-1"><a class="header-anchor" href="#debian-13" aria-hidden="true">#</a> Debian 13</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends curl ca-certificates

# curl https://repo.cloudlinux.com/kernelcare/kernelcare.gpg -o /usr/share/keyrings/kcare-eportal.gpg

# cat &gt; /etc/apt/sources.list.d/kcare-eportal.list &lt;&lt;EOL
deb [signed-by=/usr/share/keyrings/kcare-eportal.gpg] https://repo.cloudlinux.com/kcare-eportal/debian/13 kcare main
EOL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Install ePortal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># apt update &amp;&amp; apt install -y --no-install-recommends kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="docker-image" tabindex="-1"><a class="header-anchor" href="#docker-image" aria-hidden="true">#</a> Docker image</h3><div class="tip custom-block"><p class="custom-block-title">Note</p><p>For production deployments, use the <code>-d</code> flag (detached mode) to run the container in the background. For interactive testing or debugging, you can use <code>-it</code> flags instead.</p></div><p>Simple run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm --network=host kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Run with persistent volume:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm --network=host \\
    -v eportal-volume:/var/lib/eportal/data/ \\
    kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>or mount:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm --network=host \\
    -v /var/lib/eportal/data:/var/lib/eportal/data/ \\
    kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>run with unprevileged user:</p><p><strong>WARNING</strong>: Volume or mount should be provided, and the owner of the host folder should be equal to the UID that is used with <code>--user</code> option. <code>--network=host</code> option can&#39;t be used in this mode.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm \\
    -v /var/lib/eportal/data:/var/lib/eportal/data/ \\
    --user &lt;uid of user&gt; kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The ePortal image uses several environment variables which are useful for the advanced configuration</p><table><thead><tr><th>Environment variable</th><th>Description</th><th>Default value</th></tr></thead><tbody><tr><td>EPORTAL_SERVER_STATS_PERIOD</td><td>timeout in seconds when eportal send usage statistics</td><td>1 day</td></tr><tr><td>EPORTAL_AUTO_UPDATE_PERIOD</td><td>timeout in seconds when eportal tries to pull updates</td><td>10 min</td></tr><tr><td>EPORTAL_LIMIT_PATCHSETS</td><td>process at most N latest patchsets from patchserver</td><td>None (all)</td></tr><tr><td>EPORTAL_PROXY</td><td>proxy connection string</td><td>unset</td></tr><tr><td>EPORTAL_REDUCED_REPORT</td><td>do not send detailed stats to patchserver</td><td>False</td></tr><tr><td>EPORTAL_NODE_URL</td><td>this node URL (replication setup)</td><td>unset</td></tr><tr><td>EPORTAL_LEADER_URL</td><td>leader node URL (replication setup)</td><td>unset</td></tr><tr><td>EPORTAL_REPLICATION_SHARED_KEY</td><td>shared secret for replicas (replication setup)</td><td>unset</td></tr><tr><td>EPORTAL_REPLICATION_CHECK_CERT</td><td>whether to check node certificate</td><td>True</td></tr><tr><td>EPORTAL_REPLICATION_CLEAN_AGE</td><td>replication log retention period in seconds</td><td>7 days</td></tr><tr><td>EPORTAL_REPLICATION_CLEAN_AGGRESSIVE_AGE</td><td>retention period for aggressive policy</td><td>1 hour</td></tr><tr><td>EPORTAL_REPLICATION_STANDBY</td><td>passive mode for node (only receiving changes)</td><td>False</td></tr><tr><td>EPORTAL_CACHE_MODE</td><td>pass patch request directly to patchserver without preliminary downloading patchsets</td><td>False</td></tr><tr><td>EPORTAL_PATCH_SOURCE_URL</td><td>patch source</td><td>https://downloads.kernelcare.com/patch-download/</td></tr><tr><td>EPORTAL_PATCH_SOURCE_USER</td><td>patch source user, if set, will overwrite patch source configuration in UI</td><td>unset</td></tr><tr><td>EPORTAL_PATCH_SOURCE_PASSWORD</td><td>patch source password</td><td>unset</td></tr><tr><td>EPORTAL_BUNITS</td><td>enable business units feature (multi tenancy)</td><td>False</td></tr><tr><td>EPORTAL_BUNITS_LOGIN_SELECTOR</td><td>allows to select business unit when logging in</td><td>False</td></tr><tr><td>EPORTAL_RADAR_PROXY_ENABLE</td><td>enable TuxCare RADAR proxying</td><td>False</td></tr><tr><td>EPORTAL_RADAR_PROXY_BASEURL</td><td>TuxCare RADAR URL</td><td>https://radar.tuxcare.com</td></tr><tr><td>EPORTAL_SEND_CHECKIN_PERIOD</td><td>servers check-ins report period in seconds</td><td>1 day</td></tr><tr><td>EPORTAL_ENABLE_ERROR_REPORTING</td><td>send application errors to the patchserver</td><td>False</td></tr></tbody></table><p>For example, if you need to send reduced stats:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm --network=host \\
    -e EPORTAL_REDUCED_REPORT=1 \\
    -v eportal-volume:/var/lib/eportal/data/ \\
    kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Users management command should be executed in the running container. For example, to create an admin user:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker exec &lt;container-id&gt; kc.eportal -a admin -p AdminPassword
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="image-upgrade-and-downgrade" tabindex="-1"><a class="header-anchor" href="#image-upgrade-and-downgrade" aria-hidden="true">#</a> Image upgrade and downgrade</h4><p>Typically, upgrading or downgrading ePortal image does not require any additional actions.</p><p>Special cases of downgrading:</p><ul><li>Downgrade <strong>from</strong> versions &lt;= 2.11-1 is not supported</li><li>Downgrade <strong>to</strong> versions &lt;= 2.11-1 requires additional steps. For example, having data dir created with kernelcare/eportal:2.12-1, you want to downgrade to kernelcare/eportal:2.8-1. First, make a backup of eportal-volume, then proceed with</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>    docker run --rm -v eportal-volume:/var/lib/eportal/data --entrypoint=python3.8 \\
        -it kernelcare/eportal:2.8-1 /var/lib/eportal/data/migration/migratedb.py
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Then you can use kernelcare/eportal:2.8-1 image to run container as usual.</p><h2 id="allowed-hosts" tabindex="-1"><a class="header-anchor" href="#allowed-hosts" aria-hidden="true">#</a> Allowed hosts</h2><p>We must declare the list of allowed hosts in the configuration for security reasons. It help to avoid HTTP Host header attacks. According to your installation, you need to add this parameter into <a href="#config-files">ePortal config file</a>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ALLOWED_HOSTS = [&#39;node1-yourdomain.example.com&#39;, &#39;node2-yourdomain.example.com&#39;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Instead of an example, use the DNS name(s) of your ePortal server installation. Default value is <code>[]</code>.</p><h2 id="cache-mode" tabindex="-1"><a class="header-anchor" href="#cache-mode" aria-hidden="true">#</a> Cache mode</h2><p>Cache mode allows to greatly reduce disk usage requirements and speed up initial downloading step.</p><p>In cache mode ePortal downloads only lightweight meta information about patchsets and proxies patch requests from KernelCare agent to the patch server (Patch Source). Downloaded patch binaries are cached for 2 weeks and accessible for following requests directly from ePortal and doesn&#39;t consume public internet bandwidth.</p><p><img src="`+h+`" alt="Cache mode"></p><h3 id="enable-cache-mode" tabindex="-1"><a class="header-anchor" href="#enable-cache-mode" aria-hidden="true">#</a> Enable cache mode</h3><ol><li>add the following setting into the <a href="#config-files">ePortal config file</a>:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>CACHE_MODE = True
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>restart ePortal:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl restart eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>For existing installations you have to refetch meta info for existing patchsets:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kcare/kc.eportal cache-mode --fetch-meta
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="disable-cache-mode" tabindex="-1"><a class="header-anchor" href="#disable-cache-mode" aria-hidden="true">#</a> Disable cache mode</h3><ol><li>remove or comment the line below in the <a href="#config-files">ePortal config file</a>:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>CACHE_MODE = True
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>download missing patchests:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kcare/kc.eportal kcare download-missing
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>restart ePortal:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl restart eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="proxy-configuration" tabindex="-1"><a class="header-anchor" href="#proxy-configuration" aria-hidden="true">#</a> Proxy configuration</h2><p>ePortal can fetch packages and patches via a customer&#39;s proxy server.</p><p><img src="`+m+`" alt="Proxy"></p><p>On the ePortal machine, you should define the same proxy settings as you use on the command line.</p><p>To do so, add <code>PROXY = &#39;http://example.com:3128&#39;</code> into the <a href="#config-files">ePortal config file</a>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># echo &quot;PROXY = &#39;http://example.com:3128&#39;&quot; &gt;&gt; /etc/eportal/config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>ePortal also supports a SOCKS5 proxy via <code>socks5://</code> proxy scheme:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># echo &quot;PROXY = &#39;socks5://example.com:1080&#39;&quot; &gt;&gt; /etc/eportal/config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Restart ePortal (see the <a href="#stopping-starting">Stopping &amp; Starting</a> section, choose a corresponding OS).</p><h3 id="urls-to-allow" tabindex="-1"><a class="header-anchor" href="#urls-to-allow" aria-hidden="true">#</a> URLs to allow</h3><p>If ePortal is deployed behind a proxy or a restrictive firewall, allow outbound <strong>HTTPS (TCP 443)</strong> to the following hosts:</p><table><thead><tr><th>URL</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td><code>https://downloads.kernelcare.com</code></td><td>Patch source: downloads patchsets and update metadata, and sends usage statistics and error reports. Authenticated with your patch-source credentials.</td><td>Yes</td></tr><tr><td><code>https://repo.cloudlinux.com</code></td><td>TuxCare package repository. Hosts the <code>kcare-eportal</code> package and the KernelCare agent installer/packages that ePortal proxies to client servers.</td><td>Yes</td></tr><tr><td><code>https://patches.kernelcare.com</code></td><td>Patch server: ePortal proxies patch-server requests and agent doctor-report uploads here.</td><td>Yes</td></tr><tr><td><code>https://radar.tuxcare.com</code></td><td>TuxCare RADAR (default endpoint; configurable via <code>RADAR_PROXY_BASEURL</code>).</td><td>When RADAR proxying is enabled (<code>RADAR_PROXY_ENABLE</code>)</td></tr><tr><td><code>https://repo.eportal.kernelcare.com</code></td><td>Legacy ePortal package repository (older EL7 installations); also used by the <code>kc.eportal doctor</code> connectivity check.</td><td>Optional</td></tr></tbody></table><p>The <code>downloads.kernelcare.com</code> and <code>radar.tuxcare.com</code> addresses are defaults. If you point ePortal at a different patch source (<code>PATCH_SOURCE_URL</code>) or RADAR endpoint (<code>RADAR_PROXY_BASEURL</code>), allow your configured URL instead.</p><p>Installing ePortal&#39;s OS dependencies (for example, the Nginx web server) may additionally require access to your distribution&#39;s package repositories and the <a href="https://nginx.org/" target="_blank" rel="noopener noreferrer">official Nginx repository</a>.</p><h2 id="auth-configuration" tabindex="-1"><a class="header-anchor" href="#auth-configuration" aria-hidden="true">#</a> Auth configuration</h2><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><code>AUTH_RESTRICTED_INDEX</code></td><td>Allow access to the index page only for registered users</td></tr><tr><td><code>AUTH_PASSWORD_MIN_LENGTH</code></td><td>Minimal password length, default 5</td></tr><tr><td><code>AUTH_SESSION_LIFETIME</code></td><td>Session lifetime in seconds, by default session will last till browser closing</td></tr><tr><td><code>AUTH_REFRESH_SESSION</code></td><td>If <code>False</code> (default), expires session after lifetime seconds after login. If <code>True</code>, expires session after lifetime seconds of inactivity.</td></tr></tbody></table><p>You can set configuration in <a href="#config-files">ePortal config file</a>.</p><h2 id="managing-users" tabindex="-1"><a class="header-anchor" href="#managing-users" aria-hidden="true">#</a> Managing Users</h2><p>You can manage portal using <code>kc.eportal user</code> utility:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>usage: kc.eportal user [-h] [-a] [-c] [-d] [-p PASSWORD] [-r {admin,readonly}] [--note NOTE] [user]

list available users by default

positional arguments:
  user                  user name

optional arguments:
  -h, --help            show this help message and exit
  -a                    action: add new user
  -c                    action: change user
  -d                    action: delete user
  -p PASSWORD, --password PASSWORD
  -r {admin,readonly}, --role {admin,readonly}
  --note NOTE           description
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To add a user:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal user -a -p AdminPassword admin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To change user&#39;s password:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal user -c -p NewPassword admin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Set user as read-only:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal user -c -r readonly admin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="authentication-using-ldap" tabindex="-1"><a class="header-anchor" href="#authentication-using-ldap" aria-hidden="true">#</a> Authentication using LDAP</h2><p>ePortal supports LDAP authentication via bind operation. Every user should have a DN with an ability to perform bind request. ePortal doesn&#39;t sync users so you don&#39;t need to set special DN/password to access LDAP server.</p><h3 id="configuration" tabindex="-1"><a class="header-anchor" href="#configuration" aria-hidden="true">#</a> Configuration</h3><p>LDAP configuration settings are available inside the <code>Settings / LDAP</code> navigation item.</p><h4 id="url" tabindex="-1"><a class="header-anchor" href="#url" aria-hidden="true">#</a> URL</h4><p>Specifies host, port, and protocol of the LDAP server to connect to.</p><p>Format: <code>&lt;scheme&gt;://&lt;host&gt;[:port][?params]</code></p><ul><li><strong>scheme</strong>: <ul><li><code>ldap</code>: a verified encrypted TLS connection, you can specify <code>tls=0</code> to use an insecure connection;</li><li><code>ldaps</code>: an SSL connection;</li></ul></li><li><strong>host</strong>: hostname or ip of your LDAP server;</li><li><strong>port</strong>: custom port, by default 389 for <code>ldap</code> and 636 for <code>ldaps</code> scheme;</li><li><strong>params</strong>: <ul><li><code>strict_check=0</code>: enable/disable strict SSL certificate verification (enabled by default);</li><li><code>tls=0</code>: enable/disable TLS handshake on connect (enabled by default);</li><li><code>timeout=30</code>: LDAP server connection timeout (in seconds, 5 by default).</li></ul></li></ul><p>For example:</p><ul><li><code>ldap://ldap.forumsys.com?tls=0&amp;timeout=30</code>: use insecure connection with 30s connection timeout.</li></ul><h4 id="connection-string-dn-template" tabindex="-1"><a class="header-anchor" href="#connection-string-dn-template" aria-hidden="true">#</a> Connection String (DN template)</h4><p>Connection string is a DN template used in LDAP bind operation. All <code>%s</code> template placeholders will be replaced with the username from the login form. For example: <code>uid=%s,dc=example,dc=com</code></p><p>Some LDAP implementations support additional templates for bind requests:</p><ul><li>Active Directory accepts the <code>%s@example.com</code> template;</li><li><code>cn=%s,dc=example,dc=com</code> or <code>email=%s,dc=example,dc=com</code> can be also valid.</li></ul><h4 id="filter" tabindex="-1"><a class="header-anchor" href="#filter" aria-hidden="true">#</a> Filter</h4><p>Filter is an optional setting which specifies parameters for an additional LDAP search request to limit users who have access to ePortal. Usually it is a check of a group a user belongs to. If the search returns a non-empty result the user will be considered authenticated.</p><p>Format: <code>&lt;base&gt;??&lt;scope&gt;?&lt;filter&gt;</code>, is a part of <a href="https://tools.ietf.org/html/rfc2255" target="_blank" rel="noopener noreferrer">The LDAP URL Format RFC</a></p><ul><li><strong>base</strong>: a search base, a root node to perform search from;</li><li><strong>scope</strong>: a search scope; <ul><li><code>base</code>: search only for base (default);</li><li><code>one</code>: search for direct ascendants only (one level deep from base);</li><li><code>sub</code>: search in whole tree;</li></ul></li><li><strong>filter</strong>: search filter to apply.</li></ul><p>For example: <code>dc=example,dc=com??one?(&amp;(ou=mathematicians)(uniqueMember=uid=%s,dc=example,dc=com))</code></p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>You can use a <code>%s</code> placeholder in the <code>Filter</code> setting as well. It will be replaced with the username from the login form.</p></div><h3 id="login-process" tabindex="-1"><a class="header-anchor" href="#login-process" aria-hidden="true">#</a> Login process</h3><p>When a user logs in to ePortal, ePortal checks the user credentials in the local database at first. If the credentials are found, the user will be authenticated, and only if the user credentials are not found, ePortal redirects to LDAP.</p><p>When you log in to ePortal with your LDAP credentials for the first time, a user with LDAP username, read-only permissions, and <code>LDAP</code> description is created in the database by default (<code>https://&lt;eportal&gt;/admin/user/</code>).</p><p>In the picture, you can see one user created with <code>kc.eportal</code> command line interface and two users logged in with LDAP credentials:</p><p><img src="`+v+`" alt="ldap users"></p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>All fresh LDAP users have read-only permissions. You can set admin rights on <code>User edit</code> page by turning off <code>Readonly</code> field.</p></div><h3 id="basic-setup-example" tabindex="-1"><a class="header-anchor" href="#basic-setup-example" aria-hidden="true">#</a> Basic setup example</h3><p>The following examples are based on the public test LDAP server <a href="https://www.forumsys.com/tutorials/integration-how-to/ldap/online-ldap-test-server/" target="_blank" rel="noopener noreferrer">ldap.forumsys.com</a></p><p>Here is a list of our users:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ ldapsearch -H ldap://ldap.forumsys.com -LLL -x -b &#39;dc=example,dc=com&#39; &#39;(objectClass=person)&#39; dn
dn: uid=tesla,dc=example,dc=com
dn: uid=gauss,dc=example,dc=com
...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Basic setup only checks if the provided username/password can bind to your directory service. Note: all fresh users have read-only permission so you can safely allow them to login into eportal and set correct permissions individually.</p><p>For a basic setup you should fill <code>Url</code> and <code>Connection string</code> settings:</p><table><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>URL</td><td>ldap://ldap.forumsys.com?tls=0</td></tr><tr><td>Connection string</td><td>uid=%s,dc=example,dc=com</td></tr></tbody></table><p>After that you can login using <code>gauss:password</code> or <code>tesla:password</code> credentials.</p><h3 id="filter-setup-example" tabindex="-1"><a class="header-anchor" href="#filter-setup-example" aria-hidden="true">#</a> Filter setup example</h3><p>Filter allows you to limit a set of users permitted to login into ePortal, for example users belonging to the <code>mathematicians</code> group.</p><p>Here are our example groups:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ ldapsearch -H ldap://ldap.forumsys.com -LLL -x -b &#39;dc=example,dc=com&#39; &#39;(objectClass=groupOfUniqueNames)&#39; dn
dn: ou=mathematicians,dc=example,dc=com
dn: ou=scientists,dc=example,dc=com
...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>And <code>mathematicians</code> group attributes:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ ldapsearch -H ldap://ldap.forumsys.com -LLL -x -b &#39;dc=example,dc=com&#39; &#39;(ou=mathematicians)&#39;
dn: ou=mathematicians,dc=example,dc=com
uniqueMember: uid=euclid,dc=example,dc=com
uniqueMember: uid=riemann,dc=example,dc=com
uniqueMember: uid=euler,dc=example,dc=com
uniqueMember: uid=gauss,dc=example,dc=com
uniqueMember: uid=test,dc=example,dc=com
ou: mathematicians
cn: Mathematicians
objectClass: groupOfUniqueNames
objectClass: top
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>ePortal LDAP settings to limit allowed users:</p><table><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>URL</td><td>ldap://ldap.forumsys.com?tls=0</td></tr><tr><td>Filter</td><td>dc=example,dc=com??one?(&amp;(ou=mathematicians)(uniqueMember=uid=%s,dc=example,dc=com))</td></tr><tr><td>Connection string</td><td>uid=%s,dc=example,dc=com</td></tr></tbody></table><p>The filter idea is to find the <code>mathematicians</code> group which has an attribute <code>uniqueMember</code> equal to DN of our user who tries to login. After that you can login using <code>gauss:password</code> but not <code>tesla:password</code> credentials.</p><h2 id="accessing-eportal" tabindex="-1"><a class="header-anchor" href="#accessing-eportal" aria-hidden="true">#</a> Accessing ePortal</h2><p>To access KernelCare.eportal management console, connect to <strong>http://YOUR_IP/admin</strong> and enter your login &amp; password.</p><p><img src="`+g+'" alt="login screen"></p><p>You can manage your login information using the <a href="#managing-users">kc.eportal tool</a></p><h2 id="patchset-deployment" tabindex="-1"><a class="header-anchor" href="#patchset-deployment" aria-hidden="true">#</a> PatchSet deployment</h2><p>ePortal has a built-in mechanism to download the latest patchsets. To start using it, click the <em>Settings</em> link in the ePortal navigational bar and then click <em>Patch Source</em>. To get access, please contact <a href="mailto:sales@tuxcare.com">sales@tuxcare.com</a> and request your ePortal access credentials.</p><p><img src="'+b+'" alt="patch source"></p><p>You can choose only a limited set of distros to fetch to reduce disk space and network bandwidth requirements. Once you set up patch source access info, you will get to a list of available patchsets.</p><p><img src="'+f+'" alt="dashboard"></p><ul><li><p><strong>Usage</strong>: amount of servers using particular patchset on any feed. You can click on the number to see a list of servers using the patchset. You can filter the patchset list to show only patchsets that are in use by using the Usage column filter.</p></li><li><p><strong>Patchsets</strong>: name of the patchset. Click on a name will show patchset changelog.</p></li><li><p><strong>Distribution</strong>: shows the Linux distributions that this patchset supports. This column helps you identify which patchsets are relevant for your environment. You can use the <a href="#filtering-patchsets">distribution filter</a> to view only patchsets for specific distributions.</p></li><li><p><strong>Feed name</strong>: cells show patchset deployment and server usage status on particular feed. Numbers are also clickable to filter server list.</p></li><li><p><strong>Manage</strong>: opens dialog to enable/disable the patchset.</p></li></ul><h3 id="patchset-deployment-statuses" tabindex="-1"><a class="header-anchor" href="#patchset-deployment-statuses" aria-hidden="true">#</a> Patchset deployment statuses</h3><p>The dashboard displays different statuses for patchsets in each feed column:</p><ul><li><p><strong>Enabled</strong>: The patchset is enabled and available for servers to use.</p></li><li><p><strong>Disabled</strong>: The patchset has been disabled by the administrator. It remains in the feed but is not available to servers.</p></li><li><p><strong>Blocked</strong>: The patchset is blocked on the patchserver, indicating it should not be used (e.g., due to known issues). Blocked patchsets are automatically disabled in ePortal and cannot be managed through the UI.</p></li><li><p><strong>Undeployed</strong>: The patchset has been downloaded but is not yet deployed to the feed.</p></li><li><p><strong>Not downloaded</strong>: The patchset has not been downloaded to ePortal yet.</p></li><li><p><strong>Not available</strong>: The patchset is unavailable for the feed (disabled on the patchserver but not blocked).</p></li><li><p><strong>Enabled (!)</strong>: Warning status - the patchset is enabled in ePortal but has been disabled or is no longer available on the patchserver. This indicates a conflict between the local ePortal configuration and the patchserver state. Possible causes include:</p><ul><li>The patchset was disabled on the patchserver after it was enabled in ePortal (e.g., due to discovered issues, deprecation, or replacement)</li><li>The patchset may have been removed from the patchserver for a specific feed or channel</li></ul><p>When you see this status, you should review the patchset and consider disabling it in ePortal or updating to a newer patchset if available. Servers using this patchset may encounter issues.</p></li></ul><h3 id="filtering-patchsets" tabindex="-1"><a class="header-anchor" href="#filtering-patchsets" aria-hidden="true">#</a> Filtering patchsets</h3><p>You can filter patchsets on the dashboard page:</p><ul><li><p><strong>Usage filter</strong>: Filter to show only patchsets that are currently in use by servers (i.e., have at least one server actively using them). This helps you focus on active patchsets or identify which ones can be safely removed. See the <a href="#patchset-deployment">Usage column</a> description above for more details.</p></li><li><p><strong>Distribution filter</strong>: Filter patchsets based on Linux distribution. This allows you to view only patchsets relevant to specific distributions (e.g., Ubuntu, Debian, RHEL-based), making it easier to manage patchsets for your environment. The filter works with the <a href="#patchset-deployment">Distribution column</a> to help you find relevant patchsets.</p></li><li><p><strong>Show unavailable patchsets</strong>: By default, patchsets that became unavailable (disabled on the patchserver) are hidden from the dashboard. Enable this toggle to display all patchsets, including those that are unavailable. This can be useful for troubleshooting or viewing the complete list of patchsets.</p></li></ul><h3 id="manage-patchset-page" tabindex="-1"><a class="header-anchor" href="#manage-patchset-page" aria-hidden="true">#</a> Manage patchset page</h3><p><img src="'+x+`" alt="manage patchsets"></p><p>In this dialog you can control which patchsets will be enabled/disabled on corresponding feeds.</p><ul><li><p><strong>Enable all up to this patchset</strong>: action will enable all patchsets (excluding <strong>disabled</strong>) up to this patchset and mark them as <strong>Enabled</strong>. This action skips any patchsets that are currently disabled, so they remain disabled even when using this bulk enable action.</p></li><li><p><strong>Enable</strong>: action will enable only the current patchset and mark it as <strong>Enabled</strong>. If the patchset is not yet deployed, it will be downloaded and deployed first.</p></li><li><p><strong>Disable</strong>: action will disable only the current patchset and mark it as <strong>Disabled</strong>. Disabled patchsets are immune to auto-update and mass-enabling via <strong>Enable all up to this patchset</strong> action. The patchset remains in the feed but is marked as disabled.</p></li><li><p><strong>Undeploy down to this patchset</strong>: action will undeploy the selected patchset and all newer patchsets in the feed and mark them as <strong>Undeployed</strong>. Older patchsets remain available in the feed.</p></li></ul><p>(see the <a href="#patchset-deployment-statuses">Patchset deployment statuses</a> section for details about possible patchset statuses)</p><p>To disable a patchset from the CLI, run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal --unroll 16012017_1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Or use the stream-specific commands:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal kcare unroll 16012017_1
# kc.eportal libcare unroll U20210129_02
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>If you want to remove a patchset instead of just disabling it, you can use the <code>--delete</code> option:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal kcare unroll 16012017_1 --delete
# kc.eportal libcare unroll U20210129_02 --delete
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="automatic-updates" tabindex="-1"><a class="header-anchor" href="#automatic-updates" aria-hidden="true">#</a> Automatic updates</h3><p>You can configure automatic updates by enabling Autoupdate on the desired feeds via LivePatching -&gt; Feeds.</p><div class="danger custom-block"><p class="custom-block-title">Note</p><p>The <strong>default feed</strong> cannot be configured via the Settings page to receive automatic updates. See the next section on configuring automatic updates for the <strong>default feed</strong>.</p></div><h3 id="automatic-updates-on-default-feed" tabindex="-1"><a class="header-anchor" href="#automatic-updates-on-default-feed" aria-hidden="true">#</a> Automatic updates on default feed</h3><p>It is possible to configure automatic updates on the <strong>default feed</strong> by creating a cron job. The following commands can be used to receive these updates.</p><p>The command below determines if the latest patchsets are available and installs them to the <strong>default feed</strong>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal --get-latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="script-to-deploy-release-from-a-file" tabindex="-1"><a class="header-anchor" href="#script-to-deploy-release-from-a-file" aria-hidden="true">#</a> Script to deploy release from a file</h3><p>If you have no opportunity to connect your ePortal server to the KernelCare patch server to download patchsets directly from it, you can do it manually.</p><p>If you have a location with already downloaded patchsets, and would like to identify the latest patchset file to be moved, you can compare the lists of archives you have with the content of the <code>/usr/share/kcare-eportal/arch/</code> folder.</p><p>After that, upload the selected patchsets to your ePortal server and run the <code>kc.eportal --deploy</code> command for each of them.</p><h4 id="example" tabindex="-1"><a class="header-anchor" href="#example" aria-hidden="true">#</a> Example</h4><p>Lets find out the difference between a test and a production ePortal instances:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ comm -23 \\
    &lt;(ssh eportal-test &quot;ls /usr/share/kcare-eportal/arch/K*.tar.bz2&quot; | sort -h) \\
    &lt;(ssh eportal-prod &quot;ls /usr/share/kcare-eportal/arch/K*.tar.bz2&quot; | sort -h) | tee patchsets.diff
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Upload patchsets to the production:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ cat patchsets.diff | xargs -Phav {} rsync -iv eportal-test:{} /tmp/
$ rsync -Phav /tmp/K*.tar.bz2 eportal-prod:/tmp/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Run the deployment tool with patchset file name as a parameter:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ ssh eportal-prod &#39;ls /tmp/K*.tar.bz2 | sort -h | xargs -n1 kc.eportal kcare deploy&#39;
2021-12-02 01:25:06,555 - eportal.patches - INFO - K04082020_1 was enabled in main
...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="danger custom-block"><p class="custom-block-title">Note</p><p>Please note that procedure above should be done for all other types of patchsets (like libcare) <em>separately</em>. Use corresponding file prefixes and commands like <code>kc.eportal libcare deploy</code>.</p></div><h3 id="clean-obsolete-releases" tabindex="-1"><a class="header-anchor" href="#clean-obsolete-releases" aria-hidden="true">#</a> Clean obsolete releases</h3><p>The list of provided patchsets is reduced once in a month (old patchsets that have newer versions are removed), but resources are not deleted from ePortal machine. The control of resource deletion is in charge of the ePortal administrator. To free disk space on ePortal old release resources could be removed.</p><p>To check what releases will be removed:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># DRY_RUN=1 kc.eportal --clean-releases
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To remove obsolete releases:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal --clean-releases
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="libcare-patchset-deployment" tabindex="-1"><a class="header-anchor" href="#libcare-patchset-deployment" aria-hidden="true">#</a> LibCare PatchSet Deployment</h2><p>Starting from version 1.18, ePortal supports the LibCare patchset management. It is accessible from the <code>Patches / LibCare</code> navigation item. LibCare patches use the same Patch Source credentials, and you don&#39;t need to perform additional configuration.</p><p><img src="`+y+`" alt="libcare feed"></p><h3 id="disable-arbitrary-patchset" tabindex="-1"><a class="header-anchor" href="#disable-arbitrary-patchset" aria-hidden="true">#</a> Disable arbitrary patchset</h3><p>To disable a patchset, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>kc.eportal kcare unroll K20210129_02
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>If you want to remove patchsets instead of disabling them, you can use the <code>--delete</code> option:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>kc.eportal kcare unroll K20210129_02 --delete
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="cli-to-install-the-latest-patchsets" tabindex="-1"><a class="header-anchor" href="#cli-to-install-the-latest-patchsets" aria-hidden="true">#</a> CLI to install the latest patchsets</h3><p>To update the default feed, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal libcare update
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To update the <code>test</code> feed, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal libcare update --feed test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To update all auto-feeds, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal libcare auto-update
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="cli-to-deploy-patchset-from-archive" tabindex="-1"><a class="header-anchor" href="#cli-to-deploy-patchset-from-archive" aria-hidden="true">#</a> CLI to deploy patchset from archive</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ kc.eportal libcare deploy --help
usage: kc.eportal libcare deploy [-h] [--feed FEED] [--disabled] archive

positional arguments:
  archive      path to archive

optional arguments:
  -h, --help   show this help message and exit
  --feed FEED  feed to deploy archive to
  --disabled   do not enable patchset after deploy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>For example:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal libcare deploy --feed test /tmp/U20210129_02.tar.bz2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This command will deploy and enable the <code>U20210129_02</code> patchset in to the <code>test</code> feed.</p><h2 id="qemu-patchset-deployment" tabindex="-1"><a class="header-anchor" href="#qemu-patchset-deployment" aria-hidden="true">#</a> QEMU PatchSet Deployment</h2><div class="danger custom-block"><p class="custom-block-title">Note</p><p>QemuCare is being deprecated. No new patchsets have been released since January 2025.</p><p>Support for QemuCare will be removed in ePortal 2.23 and KernelCare 3.4 (February 2026). To continue using existing Qemu patchsets, use older versions of ePortal and KernelCare that include QemuCare support.</p></div><p>Qemu patchsets are accessible from the <code>Patches / QEMUcare</code> navigation item. QEMU patchsets use the same Patch Source credentials, and you don&#39;t need to perform additional configuration.</p><p><img src="`+k+`" alt="qemu feed"></p><h3 id="command-to-install-the-latest-patchsets" tabindex="-1"><a class="header-anchor" href="#command-to-install-the-latest-patchsets" aria-hidden="true">#</a> Command to install the latest patchsets</h3><p>To update the default feed, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal qemu update
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To update the <code>test</code> feed, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal qemu update --feed test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To update all auto-feeds, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal qemu auto-update
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="command-to-deploy-patchset-from-archive" tabindex="-1"><a class="header-anchor" href="#command-to-deploy-patchset-from-archive" aria-hidden="true">#</a> Command to deploy patchset from archive</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ kc.eportal qemu deploy --help
usage: kc.eportal qemu deploy [-h] [--feed FEED] [--disabled] archive

positional arguments:
  archive      path to archive

optional arguments:
  -h, --help   show this help message and exit
  --feed FEED  feed to deploy archive to
  --disabled   do not enable patchset after deploy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>For example:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal qemu deploy --feed test /tmp/U20210818_01-qemu.tar.bz2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This command will deploy and enable the <code>U20210818_01-qemu</code> patchset in to the <code>test</code> feed.</p><h2 id="managing-keys" tabindex="-1"><a class="header-anchor" href="#managing-keys" aria-hidden="true">#</a> Managing Keys</h2><p>To register new servers you need to create a KernelCare key that will be used for server registration. To go to the list of keys, click the <em>Keys</em> navigation item.</p><p><img src="`+w+'" alt="keys"></p><ul><li>To edit a key, click <img src="'+P+'" alt="edit keys">. The <em>Edit</em> tab opens.</li><li>To remove a key, click <img src="'+_+'" alt="remove keys">. Please note, that removing the key would remove all servers under that key.</li><li>Click a key to go to Servers tab with the list of <a href="#managing-servers">servers registered</a> under that key. You can also remove servers on that tab.</li></ul><p>To create a new registration click <em>Create</em> tab.</p><p><img src="'+E+`" alt="create key"></p><p>Fill in the following fields:</p><ul><li><strong>Key</strong> - you can provide a key value or leave the field empty, so an automatically generated key will be used</li><li><strong>Description</strong> - you can provide a description for the key</li><li><strong>Server Limit</strong> - the amount of servers that can be registered under that key</li><li><strong>Feed</strong> - select a specific feed or leave empty.</li><li><strong>Products</strong> - limit allowed products can be used with the key.</li></ul><p>Available products:</p><ul><li><strong>KernelCare</strong>/<strong>LibCare</strong>/<strong>QemuCare</strong>/<strong>DBCare</strong>: allow only patches of selected type (QemuCare product is being depricated).</li><li><strong>Enterprise Support for AlmaLinux - ESU</strong>: allow access to the Extended Security Updates and FIPS repositories.</li></ul><p>Products can be mixed to limit access to a particular set of patch types. For example:</p><ul><li><strong>KernelCare</strong> + <strong>LibCare</strong>: allow access only to kernel and lib patches.</li></ul><p>For Enterprise Support for AlmaLinux deployment instructions please see the <a href="#deploying-enterprise-support-for-almalinux">dedicated section</a></p><p>Click <em>Save</em> to add the key. The new registration key will be created and added to the list. The key itself will be used as a part of the registration command on an individual server.</p><p>Click <em>Save and Add Another</em> to save this key and add one more key.</p><p>Click <em>Save and Continue Editing</em> to add the key and open the key edit tab.</p><p>Click <em>Cancel</em> to return to the key list tab without adding a new key.</p><h3 id="cli-to-manage-keys" tabindex="-1"><a class="header-anchor" href="#cli-to-manage-keys" aria-hidden="true">#</a> CLI to manage keys</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ kc.eportal key --help
usage: kc.eportal key [-h] [-a] [-c] [--note NOTE] [--server-limit SERVER_LIMIT] [--feed FEED]
                      [--product {kernel,libcare,qemu,tuxcare-esu}] [--default-products]
                      [key]

list available keys by default

positional arguments:
  key                   key name

optional arguments:
  -h, --help            show this help message and exit
  -a                    action: add new key
  -c                    action: change key
  --note NOTE           key description
  --server-limit SERVER_LIMIT
                        maximum number of servers allowed
  --feed FEED           feed to associate key to
  --product {kernel,libcare,qemu,tuxcare-esu}
                        products available for the key, can be specified multiple times
  --default-products    set default product list (KernelCare, LibCare, QEMUCare) for the key
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>List keys:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal key
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Autogenerate key:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal key -a
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Create key with specified value:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal key -a test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Set feed to key:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal key -c test --feed test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="managing-servers" tabindex="-1"><a class="header-anchor" href="#managing-servers" aria-hidden="true">#</a> Managing Servers</h2><p>You can see servers belonging to the key by clicking on the key itself in the <a href="#managing-keys">Managing Keys</a> interface.</p><p><img src="`+T+'" alt="server list"></p><p>The screen shows servers registered under the key, their IP, hostname, effective kernel as well as the time of registration and last check in.</p>',305)),t("p",null,[e[1]||(e[1]=a("The ",-1)),e[2]||(e[2]=t("strong",null,"Check-in",-1)),e[3]||(e[3]=a(" / ",-1)),e[4]||(e[4]=t("strong",null,"last check in",-1)),e[5]||(e[5]=a(" time is when the agent last completed a successful check-in to ePortal. With automatic updates enabled, that happens on the ",-1)),e[6]||(e[6]=t("strong",null,"same schedule",-1)),e[7]||(e[7]=a(" as the client’s periodic patch check (by default every four hours)—it is not a separate “heartbeat.” See ",-1)),e[8]||(e[8]=t("a",{href:"#kernelcare-enterprise-client-config-file"},"KernelCare Enterprise client config file",-1)),e[9]||(e[9]=a(" and ",-1)),s(i,{to:"/live-patching-services/#config-options"},{default:r(()=>e[0]||(e[0]=[a("Config options",-1)])),_:1,__:[0]}),e[10]||(e[10]=a(" for ",-1)),e[11]||(e[11]=t("code",null,"AUTO_UPDATE",-1)),e[12]||(e[12]=a(" and related settings.",-1))]),e[27]||(e[27]=n('<p>To view the list of all servers IDs that are connected to the particular key, do the following:</p><ul><li>In the UI go to the page with the list of keys. Then click the particular key. The list of servers connected to this key will be displayed.</li></ul><p>To view the list of all servers, use the <span class="notranslate"><em>Servers</em></span> menu on the navigation bar and select <em>Servers</em> from the dropdown menu. The dropdown menu also provides access to <em>Server tags</em> and <em>Overview</em> pages.</p><p><img src="'+A+`" alt="eportal servers"></p><div class="tip custom-block"><p class="custom-block-title">Clickable counters</p><p>The counters displayed on the Servers page are clickable. Clicking on any counter will filter the server list to show only servers matching that criteria. For example, clicking on a counter showing &quot;KCare active&quot; will filter to show only servers with KernelCare actively reporting. This provides quick navigation and filtering capabilities. See also the <a href="#overview-page">Overview page</a> for similar interactive features.</p></div><p>Also you can use CLI to see pairs of key/number of servers run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ kc.eportal --list-servers
Count | Key
----- + --------------------------------
    0 | 2shcolu7Y1x6885Q
    2 | 6J89aS44j6OmTr05
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="clean-inactive-servers" tabindex="-1"><a class="header-anchor" href="#clean-inactive-servers" aria-hidden="true">#</a> Clean inactive servers</h3><p>Servers inactive for more than 30 days can be removed using the followed command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal server clean --inactive
2 servers were deleted
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Clean-up of inactive servers can be performed automatically every day or rarer. To enable daily auto clean-up, you can add an option <code>CLEAN_INACTIVE_SERVERS_PERIOD = 3600 * 24</code> (value in seconds) in the <a href="#config-files">ePortal config file</a></p><h3 id="show-extended-check-in-statistics-in-admin-ui" tabindex="-1"><a class="header-anchor" href="#show-extended-check-in-statistics-in-admin-ui" aria-hidden="true">#</a> Show extended check-in statistics in admin UI</h3><p>A new table is added to the starting page. This table displays the following:</p><ul><li>Total number of servers.</li><li>Number of servers that checked in for the past 48 hours.</li></ul><p>The number of servers for each key is listed on the <em>Keys</em> page.</p><h2 id="managing-server-tags" tabindex="-1"><a class="header-anchor" href="#managing-server-tags" aria-hidden="true">#</a> Managing server tags</h2><p>You can use &#39;Server tags&#39; page to deal with tags.</p><p><img src="`+R+'" alt="server tags view"></p><p>Tagging is a convenient way to group servers by any criteria. For example OS, deployment environment, location, etc. You need to create a tag and then it can be assigned to a server from the <a href="#managing-servers">Managing Servers</a> interface.</p><p><img src="'+S+`" alt="tag assignment"></p><p>The tag may have an optional value. For example, this allows you to introduce a new geo location without creating a new tag for it.</p><h3 id="using-agent-cli-to-manage-tags" tabindex="-1"><a class="header-anchor" href="#using-agent-cli-to-manage-tags" aria-hidden="true">#</a> Using agent CLI to manage tags</h3><p>To add an extra Tag field for the server, run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kcarectl --tag command
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>where <code>command</code> is a parameter defined by a user. This parameter will be displayed in UI for the server. User could add multiple tags for each server. Each tag should be separated with <code>;</code> symbol.</p><p>Example:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kcarectl --tag &quot;env:prod;ubuntu&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This server has two tags : <code>env:prod</code> and <code>ubuntu</code>.</p><p><code>env:prod</code> is a parameter that has tag name <code>env</code> and the value <code>prod</code>.</p><p><img src="`+C+`" alt="tags"></p><p>To remove all tags from a particular server, run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kcarectl --tag &quot;&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Where <code>&quot;&quot;</code> is a parameter to delete the previously defined tag.</p><h2 id="feed-management" tabindex="-1"><a class="header-anchor" href="#feed-management" aria-hidden="true">#</a> Feed Management</h2><p>Feeds are intended to manage patchsets on the server, and they provide a possibility to bind a set of patchsets to a specific key. Possible use cases: for preliminary testing of patchsets, for applying updates to groups of servers with the similar hardware, etc.</p><p>To get into Feeds Management interface go to LivePatching -&gt; Feeds:</p><p><img src="`+L+'" alt="feeds"></p><p>On this page a user can manage the existing feeds: create, delete, edit.</p><p><img src="'+I+'" alt="feed menu"></p><p>Available options:</p><ul><li><p>Name - a name of a feed.</p></li><li><p>Auto update - enable and disable automatic downloading of patchsets to this feed.</p></li><li><p>Deploy after X hours - a delay in hours between the moment the patchset is available for deployment and the moment it is installed to the feed.</p></li><li><p>Channel - a patch channel to use.</p><ul><li><strong>Stable</strong>: (default) stable patchsets marked with <code>eportal</code> label on <a href="https://patches.kernelcare.com/" target="_blank" rel="noopener noreferrer">the patch server</a>.</li><li><strong>Testing</strong>: all patchsets available on <a href="https://patches.kernelcare.com/" target="_blank" rel="noopener noreferrer">the patch server</a>.</li><li><strong>Unstable</strong>: patchsets from early-access feed (not recommended).</li></ul></li></ul><p>Every 10 minutes ePortal checks for new patchsets on the main patch server. If a new patch is available, it is uploaded to the ePortal server. Note: it is uploaded but is not deployed.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>For information about configuring a client to periodically check and automatically download new patch sets, see <a href="#kernelcare-enterprise-client-config-file">client configuration</a></p></div><p>The patch availability time is considered starting from the moment a new patch appears on the ePortal, and that time is taken into account in <code>Deploy after X hours</code> option. So, if a user sets <code>Deploy after X hours = 10</code>, the patch will be deployed to the feed 10 hours after it has been downloaded to the ePortal server.</p><p>To make the feed auto-update immediately, so new patchsets are loaded to the feed immediately after they are available on ePortal, set <code>Deploy after X hours = 0</code>.</p><p>A special case is a clean installation when ePortal is installed on a new server (there aren&#39;t any downloaded archives with patches and feeds with deployed patchsets, including default feed). In this case, if a user creates a new feed and sets Deployed after X hours option right away, then all patchsets (from the oldest to the latest available) will be deployed to the feed after the specified X hours. This is because the archives are downloaded from scratch and will be considered as &quot;just appeared on ePortal&quot; - that is, all patchsets will have the same appearance time on ePortal from which the option Deploy after X hours will repel.</p><p><img src="'+O+'" alt="feed management"></p><p>On the main ePortal page, a user can set the corresponding key &lt;&gt; feed pair. This is done in the key creation interface or when editing a key.</p><p><img src="'+D+'" alt="edit key"></p><p>By default, a new key is bound to the default feed, alternatively, a user can choose a desired feed from the drop-down menu.</p><p><img src="'+q+`" alt="feed list"></p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>When removing a feed all keys attached to this feed will be moved to the default feed.</p></div><h3 id="cli-to-manage-feeds" tabindex="-1"><a class="header-anchor" href="#cli-to-manage-feeds" aria-hidden="true">#</a> CLI to manage feeds</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>~$ kc.eportal feed --help
usage: kc.eportal feed [-h] [-a] [-c] [--auto] [--no-auto] [--deploy-after hours]
                       [--channel {default,test,unstable}] [feed]

list available feeds by default

positional arguments:
  feed                  feed name

optional arguments:
  -h, --help            show this help message and exit
  -a                    action: add new feed
  -c                    action: change feed
  --auto                update feed automatically
  --no-auto             don&#39;t update feed automatically
  --deploy-after hours  deploy after specified hours
  --channel {default,test,unstable}
                        patchset channel to use for this feed
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>List feeds:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ kc.eportal feed
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Add auto updated feed:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal feed -a test --auto
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Change feed into delayed feed:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal feed -c test --deploy-after 12
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="api-keys-management" tabindex="-1"><a class="header-anchor" href="#api-keys-management" aria-hidden="true">#</a> API keys Management</h2><p>An API key may be used as an alternative to password authentication when accessing public API endpoints. API tokens provide a more secure way to authenticate APIs because they can be easily revoked without affecting each other, and you don&#39;t need to share your credentials.</p><p>To get into API keys Management interface go to Settings -&gt; API keys:</p><p><img src="`+U+'" alt="API keys"></p><p>On this page a user can manage the existing API keys: create, revoke (delete).</p><p><img src="'+N+'" alt="API key edit"></p><p>Available options:</p><ul><li>Key name - a name of the API key.</li><li>Expiration date - optional key expiration date.</li></ul><p>After generating the key, you will see a bar with a token, as in the picture below.</p><p><img src="'+F+'" alt="API key generated"></p><p>This token is not stored on the server, so you need to keep it in a safe place. Use this token in an API client as described in <a href="/eportal-api">ePortal API documentation</a>.</p><p>The API key is personal, meaning it is tied to a specific user and inherits their permissions. A user with read-only permissions can only manage their own keys, while an administrator has access to any user&#39;s API keys.</p><h2 id="overview-page" tabindex="-1"><a class="header-anchor" href="#overview-page" aria-hidden="true">#</a> Overview page</h2><p>The Overview page provides a high-level summary of all selected servers. It includes data on server uptime, CPU architecture, OS and kernel distribution, and how many servers have KernelCare (KCare) or LibCare enabled.</p><h3 id="uptime-distribution" tabindex="-1"><a class="header-anchor" href="#uptime-distribution" aria-hidden="true">#</a> Uptime distribution</h3><p>This section shows the uptime of servers where our agent is installed. Uptime refers to how long the server has been running without a reboot.</p><p>The donut chart categorizes server uptime into:</p><ul><li><strong>under 6 months</strong></li><li><strong>6 to 12 months</strong></li><li><strong>12 to 18 months</strong></li><li><strong>over 18 months</strong></li></ul><p>Additional metrics:</p><ul><li><strong>Max uptime</strong> — the longest uptime among servers with a reporting agent</li><li><strong>Average uptime</strong> — average uptime across these servers</li><li><strong>Median uptime</strong> — median uptime across these servers</li></ul><div class="tip custom-block"><p class="custom-block-title">Interactive charts</p><p>You can click on any segment of the donut chart to drill down and filter the server list. This allows you to explore which servers fall into each uptime category and view detailed information about them.</p></div><p><img src="'+K+'" alt="Uptime distribution"></p><h3 id="cpu-arch-distribution" tabindex="-1"><a class="header-anchor" href="#cpu-arch-distribution" aria-hidden="true">#</a> CPU arch distribution</h3><p>Shows the breakdown of CPU architectures detected on servers. If the architecture is not reported, it appears as <code>unknown</code>.</p><div class="tip custom-block"><p class="custom-block-title">Interactive charts</p><p>Click on any segment of the donut chart to filter the server list and view servers with that specific architecture. See also the <a href="#uptime-distribution">Uptime distribution</a> section for similar functionality.</p></div><p><img src="'+H+'" alt="Architecture distribution"></p><h3 id="os-distribution" tabindex="-1"><a class="header-anchor" href="#os-distribution" aria-hidden="true">#</a> OS distribution</h3><p>This table displays the top 10 most common operating system distributions among the selected servers, along with how many of those servers have KernelCare (KCare) or LibCare enabled:</p><ul><li><strong>KCare active</strong> — server has KCare enabled and is actively reporting</li><li><strong>KCare silent</strong> — server has KCare enabled, but is not currently reporting</li><li><strong>LibCare active</strong> — server has LibCare enabled and is actively reporting</li><li><strong>LibCare silent</strong> — server has LibCare enabled, but is not currently reporting</li></ul><p>The LibCare usage statistics show how many servers have LibCare enabled and are actively using it versus those that have it enabled but are not currently reporting. This helps you understand LibCare adoption and usage across your infrastructure.</p><p>If more than 10 OS types are detected, the rest are grouped under an <strong>&quot;Other&quot;</strong> row. A <strong>Total</strong> row summarizes all servers.</p><p><img src="'+Y+'" alt="OS distribution"></p><h3 id="kernel-distribution" tabindex="-1"><a class="header-anchor" href="#kernel-distribution" aria-hidden="true">#</a> Kernel distribution</h3><p>This section lists the top 10 kernel versions detected across the selected servers, along with how many servers are running each version with KCare enabled:</p><ul><li><strong>KCare active</strong> — server has KCare enabled and is actively reporting</li><li><strong>KCare silent</strong> — server has KCare enabled, but is not currently reporting</li></ul><p>If more than 10 kernel versions are detected, the rest are grouped under an &quot;Other&quot; row. A <strong>Total</strong> row summarizes all servers.</p><p><img src="'+M+`" alt="Kernel distribution"></p><h3 id="effective-kernels" tabindex="-1"><a class="header-anchor" href="#effective-kernels" aria-hidden="true">#</a> Effective kernels</h3><p>The Overview page also displays a list of <strong>effective kernels</strong> — the kernels that are actually in use across your servers. This differs from the <a href="#kernel-distribution">kernel distribution chart</a> above in that it shows the complete list of active kernels rather than just the top 10, helping you identify all kernel versions that need patch coverage.</p><h2 id="how-to-setup-eportal-to-use-https" tabindex="-1"><a class="header-anchor" href="#how-to-setup-eportal-to-use-https" aria-hidden="true">#</a> How to setup ePortal to use HTTPS</h2><p>Some assumptions for a server where e-portal is deployed:</p><h3 id="terminate-tls-on-eportal-public-nginx-web-server" tabindex="-1"><a class="header-anchor" href="#terminate-tls-on-eportal-public-nginx-web-server" aria-hidden="true">#</a> Terminate TLS on ePortal public nginx web server</h3><ol><li>A firewall allows connections to 443 port.</li><li>Private and public keys are downloaded on the server.</li></ol><ul><li>Edit SSL configuration template according to your certificates:</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># mv /etc/nginx/eportal.ssl.conf.example /etc/nginx/eportal.ssl.conf
# vi /etc/nginx/eportal.ssl.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Include this configuration into the main one:</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># sed -e &#39;3iinclude eportal.ssl.conf;&#39; -i /etc/nginx/conf.d/eportal.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>Restart nginx:</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># service nginx restart
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="terminate-tls-on-external-balancer" tabindex="-1"><a class="header-anchor" href="#terminate-tls-on-external-balancer" aria-hidden="true">#</a> Terminate TLS on external balancer</h3><p>You can use any reverse proxy server of choice to terminate TLS traffic and forward requests to ePortal instance. The only requirement is to provide correct <code>Host</code> and <code>X-Forwarded-Proto</code> headers.</p><p>For example balancer nginx config:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>server {
   listen       443 ssl;
   server_name  your-eportal-domain;

   # ssl stuff ...
   # ssl_certificate  ...
   # ssl_certificate_key ...

   location / {
      proxy_pass http://eportal-instance-address;
      proxy_set_header Host $http_host;
      proxy_set_header X-Forwarded-Proto https;
   }
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="update-agent-configuration" tabindex="-1"><a class="header-anchor" href="#update-agent-configuration" aria-hidden="true">#</a> Update agent configuration</h3><p>In order to communicate with e-portal, updated to https, you need to modify KernelCare configuration file on all the servers if they have IPs hard coded servers settings.</p><p>To do that, update <code>PATCH_SERVER</code> and <code>REGISTRATION_URL</code> options:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># vi /etc/sysconfig/kcare/kcare.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>So, after editing your <code>/etc/sysconfig/kcare/kcare.conf</code> should contain updated <code>PATCH_SERVER</code> and <code>REGISTRATION_URL</code> environment variables like in the example below:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>PATCH_SERVER=https://eportal_domain_name/
REGISTRATION_URL=https://eportal_domain_name/admin/api/kcare
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>As an alternative you can use ePortal&#39;s special endpoint to update patch server address:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl -s https://eportal_domain_name/set-patch-server | bash
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="high-availability" tabindex="-1"><a class="header-anchor" href="#high-availability" aria-hidden="true">#</a> High availability</h2><p>Starting from version 1.28, ePortal supports application level replication. It allows to propagate changes in both ways – from a leader to followers and from followers to the leader.</p><p>Configuration settings related to replication and can be changed in <a href="#config-files">ePortal config file</a>:</p><ul><li><code>NODE_URL</code>: URL to the self instance, needed for auto-discovery purposes</li><li><code>LEADER_URL</code>: URL to the instance from where to fetch changes</li><li><code>REPLICATION_SHARED_KEY</code>: authorization key to access the replication data</li><li><code>REPLICATION_CHECK_CERT</code>: use strict TLS cert check for replication requests. It can be useful to deploy self signed certificates on replicas and get encrypted replication traffic without getting proper TLS certificate.</li><li><code>REPLICATION_CLEAN_AGE</code>: data age in seconds to leave during oplog cleanup. 7 days by default.</li><li><code>REPLICATION_CLEAN_AGGRESSIVE_AGE</code>: data age in seconds to leave during oplog cleanup for not-important operations. 1 hour by default.</li></ul><p>A leader node discovers followers automatically and after that fetches the changes.</p><p>You can use any convenient way to balance agent requests to the ePortal cluster. For example, you can add multiple IP addresses to the DNS name or use an HTTP balancer.</p><h3 id="basic-setup" tabindex="-1"><a class="header-anchor" href="#basic-setup" aria-hidden="true">#</a> Basic setup</h3><ol><li><p>Prepare two fresh ePortal instances and assign DNS name to IPs. For example:</p><ul><li>eportal1.corp -&gt; 192.168.1.11</li><li>eportal2.corp -&gt; 192.168.1.12</li><li>eportal.corp -&gt; 192.168.1.11, 192.168.1.12</li></ul></li><li><p>Let&#39;s choose <code>eportal1</code> as a leader and <code>eportal2</code> as a follower. <code>eportal.corp</code> is a cluster hostname to use on servers with KernelCare agent.</p><div class="danger custom-block"><p class="custom-block-title">Warning!</p><p>Please do not use a cluster hostname to perform operations with the ePortal admin UI.</p></div></li><li><p>On the <code>eportal1</code> define <code>NODE_URL</code> and <code>REPLICATION_SHARED_KEY</code> in the configuration file:</p></li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>NODE_URL = &#39;http://eportal1.corp&#39;
REPLICATION_SHARED_KEY = &#39;secret&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>On the <code>eportal2</code> define <code>NODE_URL</code>, <code>LEADER_URL</code> and <code>REPLICATION_SHARED_KEY</code>:</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>NODE_URL = &#39;http://eportal2.corp&#39;
LEADER_URL = &#39;http://eportal1.corp&#39;
REPLICATION_SHARED_KEY = &#39;secret&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="5"><li>That&#39;s it. After ePortal restart on both hosts, changes on the <code>eportal1</code> will be replicated to the <code>eportal2</code> instance and vice versa.</li></ol><div class="tip custom-block"><p class="custom-block-title">Note</p><p>You can change the KernelCare agent settings to point to a cluster hostname via:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl -s http://eportal.corp/set-patch-server | bash
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><h3 id="adding-node-to-an-existing-eportal-instance" tabindex="-1"><a class="header-anchor" href="#adding-node-to-an-existing-eportal-instance" aria-hidden="true">#</a> Adding node to an existing ePortal instance</h3><p>If you already have a working ePortal instance, you can setup a second node, define <code>NODE_URL</code> and <code>LEADER_URL</code> on both instances and trigger full sync on the follower instance:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[root@eportal2.corp]$ kc.eportal replication --full-sync
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="monitoring" tabindex="-1"><a class="header-anchor" href="#monitoring" aria-hidden="true">#</a> Monitoring</h3><p>You can use <code>kc.eportal replication --short-status</code> CLI command to check replication status. It exits with code <code>1</code> if there are some issues with replication and outputs JSON:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>{
  &quot;ok&quot;: true,       // overall health status
  &quot;lag&quot;: 1,         // overall replication lag in seconds
  &quot;last_sync&quot;: 1,   // overall sync delta in seconds (how many seconds ago was successful communication with an upstream)
  &quot;upstream&quot;: {     // per upstream metrics
    &quot;node2&quot;: {
      &quot;ok&quot;: true
      &quot;lag&quot;: 1,
      &quot;last_sync&quot;: 1,
    },
    &quot;node3&quot;: {
      &quot;ok&quot;: true
      &quot;lag&quot;: 1,
      &quot;last_sync&quot;: 1,
    }
  }
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="other-replication-setups" tabindex="-1"><a class="header-anchor" href="#other-replication-setups" aria-hidden="true">#</a> Other replication setups</h3><p>For one leader and two follower setup:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>     +-&gt; leader &lt;-+
     |            |
     |            |
follower1       follower2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>there is a chance to lose a <code>leader</code> node and <code>follower1</code>/<code>follower2</code> will not communicate with each other. To mitigate this issue, you can deploy a ring replication:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>  +-&gt; node1 --+
  |           |
  |           v
node2 &lt;---- node3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>where each instance follows another node.</p><h3 id="caveats" tabindex="-1"><a class="header-anchor" href="#caveats" aria-hidden="true">#</a> Caveats</h3><ol><li><p>Replication uses HTTP transport. If you deploy ePortal without SSL termination, the replication data will be transferred as-is unencrypted.</p></li><li><p>For a round-robin balancer setups (DNS or HTTP balancer round-robin) KernelCare agent can run onto replication lag in case of sequential registration and following update. You can introduce 10s timeout or repeat in your configuration management logic to mitigate the issue.</p></li><li><p>Replication log is kept for 7 days. If a node loses connectivity for more than 7 days it skips some changes.</p></li></ol><h2 id="deploying-kernelcare-enterprise" tabindex="-1"><a class="header-anchor" href="#deploying-kernelcare-enterprise" aria-hidden="true">#</a> Deploying KernelCare Enterprise</h2><p>You can find instructions to install KernelCare agent on http://your-eportal-domain/admin/docs/.</p><p>To install agent through ePortal you can use special endpoint <code>http://your-eportal-domain/install-kernelcare</code>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># export KCARE_MAILTO=admin@mycompany.com
# curl -s http://eportal.mycompany.com/install-kernelcare | bash
# kcarectl --register my-key
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Exporting <code>KCARE_MAILTO</code> is an optional step, it helps to configure corresponding entry in <code>/etc/cron.d/kcare-cron</code> to receive all notifications related to failed KernelCare updates.</p><h3 id="kernelcare-enterprise-client-config-file" tabindex="-1"><a class="header-anchor" href="#kernelcare-enterprise-client-config-file" aria-hidden="true">#</a> KernelCare Enterprise client config file</h3><p>KernelCare Enterprise client configuration file is located in <code>/etc/sysconfig/kcare/kcare.conf</code></p><p>Example:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>AUTO_UPDATE=True
PATCH_SERVER=http://10.1.10.115/
REGISTRATION_URL=http://10.1.10.115/admin/api/kcare
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If <code>AUTO_UPDATE</code> is set to <code>True</code>, the client runs every 4 hours. Each run <strong>checks in</strong> to ePortal (this updates <strong>Check-in</strong> / <strong>last check in</strong> in the admin UI) and tries to download and apply the latest patchsets—so check-in frequency is the same as the automatic “look for updates” cadence, not an extra timer.</p><p><code>PATCH_SERVER</code> - server from which patchsets will be downloaded</p><p><code>REGISTRATION_URL</code> - URL used to register/unregister server</p><h3 id="deployment-automation" tabindex="-1"><a class="header-anchor" href="#deployment-automation" aria-hidden="true">#</a> Deployment Automation</h3><p>It is possible to use automation tools like Ansible/Puppet/Chef/Salt to install and operate KernelCare on a big number of systems.</p><p>The deployment process includes:</p><ul><li>Running <code>http://your-eportal-domain/install-kernelcare</code> script. You can pre-download it (verify checksum) or directly execute <code>curl -s http://your-eportal-domain/install-kernelcare | bash</code>.</li><li>Registering KernelCare agents using an activation key</li></ul><h4 id="ansible" tabindex="-1"><a class="header-anchor" href="#ansible" aria-hidden="true">#</a> Ansible</h4><p>To start the automated deployment, you need to specify the following information:</p>`,166)),t("ul",null,[t("li",null,[t("p",null,[e[14]||(e[14]=a("ePortal server name (or IP) in the ",-1)),e[15]||(e[15]=t("code",null,"eportal_srv",-1)),e[16]||(e[16]=a(" Ansible variable. Other config file options can be found at ",-1)),s(i,{to:"/live-patching-services/#config-options"},{default:r(()=>e[13]||(e[13]=[a("Config Options",-1)])),_:1,__:[13]}),e[17]||(e[17]=a(" and ",-1)),e[18]||(e[18]=t("a",{href:"#kernelcare-enterprise-client-config-file"},"KernelCare client config file",-1)),e[19]||(e[19]=a(" (ePortal).",-1))])]),e[20]||(e[20]=t("li",null,[t("p",null,[a("an activation key in the "),t("code",null,"activation_key"),a(" Ansible variable. Activation keys can be generated in ePortal as described in "),t("a",{href:"#managing-keys"},"Managing Keys"),a(" (ePortal).")])],-1))]),e[28]||(e[28]=n(`<p>Ansible playbook for deployment phase may look like:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>- hosts: kernelcare
  vars:
    eportal_srv: http://192.168.250.19
    activation_key: my-key
  tasks:
    - name: Download the installation shell script
      get_url:
        url: &quot;{{ eportal_srv }}/install-kernelcare&quot;
        dest: /root/kc-install.sh
        mode: &#39;0700&#39;

    - name: Run the installation shell script
      command: /root/kc-install.sh

    - name: register KernelCare agents
      command: /usr/bin/kcarectl --register {{ activation_key }}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ansible playbook file example for KernelCare agent removal:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>- hosts: kernelcare
  tasks:
    - name: unregister KernelCare agents
      command: /usr/bin/kcarectl --unregister
      ignore_errors: yes
      args:
        removes: /usr/bin/kcarectl

    - name: remove kernelcare package
      package:
        name: kernelcare
        state: absent
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="changing-eportal-ipdomain" tabindex="-1"><a class="header-anchor" href="#changing-eportal-ipdomain" aria-hidden="true">#</a> Changing ePortal IP/domain</h3><p>You can change ePortal address at any moment by calling two special endpoints on hosts with KernelCare agent:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl -s http://your-eportal-domain/set-kernelcare-repo | bash
# curl -s http://your-eportal-domain/set-patch-server | bash
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>set-kernelcare-repo</code> configures new package repo to download agent updates through ePortal.</li><li><code>set-patch-server</code> configures new address of patch server.</li></ul><h2 id="deploying-enterprise-support-for-almalinux" tabindex="-1"><a class="header-anchor" href="#deploying-enterprise-support-for-almalinux" aria-hidden="true">#</a> Deploying Enterprise Support for AlmaLinux</h2><p>You can find instructions on how to set up <a href="https://docs.tuxcare.com/enterprise-support-for-almalinux/" target="_blank" rel="noopener noreferrer">Enterprise Support for AlmaLinux</a> on http://your-eportal-domain/admin/docs/</p><p>tuxctl is the setup tool for TuxCare&#39;s Extended Security Updates product for AlmaLinux. To set up <code>tuxctl</code> through ePortal you can use a special endpoint <strong>http://your-eportal-domain/install-tuxcare</strong>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl -s http://eportal.mycompany.com/install-tuxcare | bash
# tuxctl --license-key my-key
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Where <code>my-key</code> should have the <code>Enterprise Support for AlmaLinux - ESU</code> product enabled.</p><h2 id="migrate-eportal" tabindex="-1"><a class="header-anchor" href="#migrate-eportal" aria-hidden="true">#</a> Migrate ePortal</h2><p>Here is a procedure to migrate feed/server/key configuration and patchsets data from one ePortal to another. ePortal version on a new host should be &gt;=1.18 and equal or greater than on an old host.</p><p>If you migrate from Debian-based to Debian-based system you can simply:</p><ul><li>Stop ePortal on both hosts.</li><li>Copy <code>/var/lib/eportal</code> to a new host. Note: directory owner must stay as <code>eportal:eportal</code>.</li><li>Copy config <code>/etc/eportal/config</code> if it exists.</li><li>Run migration <code>/usr/share/kcare-eportal/migratedb.py</code> on a new host.</li><li>Start ePortal on a new host.</li></ul><p>Migration from RHEL-based distro is more elaborate. Later we refer to a <code>$BASE_DIR</code> variable in scripts. You can export it for RHEL-based distros:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># export BASE_DIR=/usr/share/kcare-eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>or for Debian-based distros:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># export BASE_DIR=/var/lib/eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>or for docker-based installation use corresponding data directory. For example if you run a container as <code>docker run -v /var/lib/eportal/data:/var/lib/eportal/data kernelcare/eportal</code> use /var/lib/eportal/data as <code>$BASE_DIR</code>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># export BASE_DIR=/var/lib/eportal/data
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>Stop ePortal on both hosts:</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>  [old-host ~]# systemctl stop eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>  [new-host ~]# systemctl stop eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>Remove db files on a new host:</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[new-host ~]# rm $BASE_DIR/*.sqlite*
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p>Copy database files <code>$BASE_DIR/*.sqlite*</code> from an old host to a new host.</p></li><li><p>(Optional) copy runtime LDAP and Feed Source settings <code>$BASE_DIR/config/config.json</code>.</p></li><li><p>(Optional) copy ePortal web app settings <code>/usr/share/kcare-eportal/config/local.py</code> or for new ePortal <code>/etc/eportal/config</code> to <code>/etc/eportal/config</code> on a new host if it exists.</p></li><li><p>Copy <code>$BASE_DIR/instance-id</code> so our billing can know that the new ePortal was migrated and to avoid double billing.</p></li><li><p>Copy patch data <code>$BASE_DIR/{arch,resources,user-resources}</code> to a new host.</p></li><li><p>Set file owner. For RHEL-based distros:</p></li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[new-host ~]# chown -R nginx:nginx $BASE_DIR
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>For Debian-based distros:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[new-host ~]# chown -R eportal:eportal $BASE_DIR
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p>Run migration <code>/usr/share/kcare-eportal/migratedb.py</code> on a new host.</p></li><li><p>Start ePortal on the new host:</p></li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[new-host ~]# systemctl start eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="migration-to-docker-container" tabindex="-1"><a class="header-anchor" href="#migration-to-docker-container" aria-hidden="true">#</a> Migration to docker container</h3><p>Let&#39;s suppose that we&#39;re going to use dockerized eportal on the same host.</p><p>The easiest way to migrate is to reuse the data directory. It can be mounted when the container starts.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run -d --rm --network=host -v /var/lib/eportal:/var/lib/eportal/data kernelcare/eportal:latest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>If you prefer to use a named volume for data-dir then all data should be copied from <code>/var/lib/eportal</code> to the volume (see <a href="https://docs.docker.com/reference/cli/docker/container/cp/" target="_blank" rel="noopener noreferrer">Docker docs</a>)</p><p>If you have custom configuration at <code>/etc/eportal/config</code> you can pass it using environment variables or mount this configuration file directly into the container like this <code>-v /etc/eportal/config:/etc/eportal/config:ro</code></p><h2 id="backup-and-restore" tabindex="-1"><a class="header-anchor" href="#backup-and-restore" aria-hidden="true">#</a> Backup and restore</h2><h3 id="create-backup" tabindex="-1"><a class="header-anchor" href="#create-backup" aria-hidden="true">#</a> Create backup</h3><p>kc.eportal utility have an option to create a data backup</p><p><code>kc.eportal backup &lt;path_to_archive&gt;</code> - creates an archive with a backup.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal backup /var/lib/eportal/backups/eportal_$(date &#39;+%Y-%m-%d&#39;).tar.gz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="backup-databases-only" tabindex="-1"><a class="header-anchor" href="#backup-databases-only" aria-hidden="true">#</a> Backup databases only</h3><p>To backup only the databases without patchset files:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal backup-db /var/lib/eportal/backups/db_backup
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Use the <code>-v</code> or <code>--verbose</code> flag to see operation progress:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal backup-db -v /var/lib/eportal/backups/db_backup
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This is useful when you only need to backup configuration and server data without the large patchset files. For full backups including patchsets, use the <a href="#create-backup">backup command</a> instead.</p><h3 id="restore-data-from-a-backup" tabindex="-1"><a class="header-anchor" href="#restore-data-from-a-backup" aria-hidden="true">#</a> Restore data from a backup</h3><div class="danger custom-block"><p class="custom-block-title">Warning!</p><p>IMPORTANT: ePortal should be stopped before restore process.</p></div><p>The restore command supports several options to control what gets restored:</p><ul><li><code>--db</code> - restore database data only</li><li><code>--config</code> - restore config.json only</li><li><code>--instance-id</code> - restore instance ID only</li><li><code>--data</code> - restore database and config.json (default)</li><li><code>--full</code> - restore all data (databases, config, instance ID, and patchset files)</li></ul><p>See the <a href="#backup-and-restore">backup section</a> for information on creating backups.</p><p>For example, to restore everything:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl stop eportal
# kc.eportal restore --full /var/lib/eportal/backups/eportal_backup.tar.gz
# kc.eportal kcare download-missing
# kc.eportal libcare download-missing
# systemctl start eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To restore only the database and configuration:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl stop eportal
# kc.eportal restore --data /var/lib/eportal/backups/eportal_backup.tar.gz
# systemctl start eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>download-missing</code> commands ensure patchset state on disk corresponds with a state in db.</p><h3 id="backup-and-restore-for-eportal-docker-container" tabindex="-1"><a class="header-anchor" href="#backup-and-restore-for-eportal-docker-container" aria-hidden="true">#</a> Backup and restore for ePortal docker container</h3><p>Volume backup process can be performed according to the instructions given <a href="https://docs.docker.com/engine/storage/volumes/#back-up-restore-or-migrate-data-volumes" target="_blank" rel="noopener noreferrer">here</a>. For example:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run --rm --volumes-from eportal -v $(pwd):/backup ubuntu tar cvf /backup/backup.tar /var/lib/eportal/data/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>or if you want to make a backup without patchsets (only configs and the database)</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run --rm --volumes-from eportal -v $(pwd):/backup ubuntu tar
    --exclude &#39;/var/lib/eportal/data/patches&#39;
    --exclude &#39;/var/lib/eportal/data/arch&#39;
    --exclude &#39;/var/lib/eportal/data/resources&#39;
    -cvf /backup/backup.tar /var/lib/eportal/data/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That backup could be restored like this</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker run --rm --volumes-from eportal2 -v $(pwd):/backup ubuntu bash -c &quot;cd / &amp;&amp; tar xvf /backup/backup.tar&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="config-files" tabindex="-1"><a class="header-anchor" href="#config-files" aria-hidden="true">#</a> Config files</h2><ul><li>ePortal config: <code>/etc/eportal/config</code>. Config for old versions (&lt;1.35): <code>/usr/share/kcare-eportal/local.py</code>.</li><li>Web Server (nginx) config: <code>/etc/nginx/conf.d/eportal.conf</code>.</li><li>Data directory: <code>/var/lib/eportal</code>.</li><li>Legacy data directory (RHEL based distros for old versions &lt;2.6): <code>/usr/share/kcare-eportal</code>.</li></ul><h2 id="stopping-starting" tabindex="-1"><a class="header-anchor" href="#stopping-starting" aria-hidden="true">#</a> Stopping &amp; starting</h2><p>To stop/start/reload/restart configuration of nginx server:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl stop|start|reload|restart nginx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To stop/start/restart ePortal (Python):</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl stop|start|restart eportal
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="log-files" tabindex="-1"><a class="header-anchor" href="#log-files" aria-hidden="true">#</a> Log files</h2><p>ePortal log: <code>journalctl -u eportal</code></p><p>Nginx ePortal access log: <code>/var/log/nginx/access.log</code></p><p>Nginx error log: <code>/var/log/nginx/error.log</code></p><h3 id="log-rotation" tabindex="-1"><a class="header-anchor" href="#log-rotation" aria-hidden="true">#</a> Log rotation</h3><p>By default there is no predefined parameters for ePortal&#39;s logs rotation. If you want to enable it for the files listed above:</p><ul><li>Install <code>logrotate</code> package</li><li>Create/edit <code>/etc/logrotate.d/eportal</code> configuration file</li></ul><p>Example logrotate config:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>/var/log/nginx/kcare-eportal.log {
    daily
    rotate 5 # keep 5 last archives
    missingok # it&#39;s ok if there is no such file
    notifempty # do nothing if file is empty
    compress
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="nagios-zabbix-support" tabindex="-1"><a class="header-anchor" href="#nagios-zabbix-support" aria-hidden="true">#</a> Nagios &amp; Zabbix support</h2>`,85)),t("p",null,[e[23]||(e[23]=a("KernelCare.ePortal since version 1.2 supports server monitoring similar to ",-1)),s(i,{to:"/kc-agent-monitoring/#nagios-plugin"},{default:r(()=>e[21]||(e[21]=[a("Nagios",-1)])),_:1,__:[21]}),e[24]||(e[24]=a(" & ",-1)),s(i,{to:"/kc-agent-monitoring/#zabbix-template"},{default:r(()=>e[22]||(e[22]=[a("Zabbix",-1)])),_:1,__:[22]}),e[25]||(e[25]=a(" monitoring.",-1))]),e[29]||(e[29]=n(`<p>You can curl the API directly to receive the information:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>https://yourserver/admin/api/kcare/nagios/KCAREKEY
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>or you can use <a href="https://patches.kernelcare.com/downloads/nagios/check_kcare" target="_blank" rel="noopener noreferrer">https://patches.kernelcare.com/downloads/nagios/check_kcare</a> script by modifying KEY_KCARE_NAGIOS_ENDPOINT in it to point to your server (change <a href="https://cln.cloudlinux.com/clweb" target="_blank" rel="noopener noreferrer">https://cln.cloudlinux.com/clweb</a> (link to old UI) or <a href="https://cln.cloudlinux.com/console/auth/login" target="_blank" rel="noopener noreferrer">https://cln.cloudlinux.com/console/auth/login</a> (link to new UI) with <a href="https://yourserver/admin" target="_blank" rel="noopener noreferrer">https://yourserver/admin</a> ).</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Access using <code>PARTNER_LOGIN/TOKEN</code> is not supported by KernelCare.ePortal</p></div><h2 id="usage-reports" tabindex="-1"><a class="header-anchor" href="#usage-reports" aria-hidden="true">#</a> Usage reports</h2><p>In common case, usage reports are sending automatically but when it&#39;s not possible, ePortal will try to send report as an email. That requires configured Sendmail (SSMTP) on the host. You can find a short instruction below.</p><p>If mail sending attempt fails, ePortal will save the reports in <code>/usr/share/kcare-eportal/reports</code> which should be sent manually.</p><h3 id="how-to-configure-sendmail-ssmtp" tabindex="-1"><a class="header-anchor" href="#how-to-configure-sendmail-ssmtp" aria-hidden="true">#</a> How to configure Sendmail (SSMTP)</h3><p>First of all you need to install <code>ssmtp</code>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># yum install -y ssmtp
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Edit <code>/etc/ssmtp/ssmtp.conf</code> file in accordance with your SMTP server configuration. Here is a simple config file describing a common way to connect to Gmail accounts:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>root=username@gmail.com
mailhub=smtp.gmail.com:587
hostname=localhost
UseSTARTTLS=YES
AuthUser=username@gmail.com
AuthPass=xxxxxxxxxxxxxxxxxxx
FromLineOverride=YES
TLS_CA_File=/etc/ssl/certs/ca-certificates.crt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Actual location of a TLS_CA_Files depends on Linux distribution:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&quot;/etc/ssl/certs/ca-certificates.crt&quot;,                // Debian/Ubuntu/Gentoo etc.
&quot;/etc/pki/tls/certs/ca-bundle.crt&quot;,                  // Fedora/RHEL 6
&quot;/etc/ssl/ca-bundle.pem&quot;,                            // OpenSUSE
&quot;/etc/pki/tls/cacert.pem&quot;,                           // OpenELEC
&quot;/etc/pki/ca-trust/extracted/pem/tls-ca-bundle.pem&quot;, // CentOS/RHEL 7
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Also you could get if from:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># curl-config --ca
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Now you can test a connection:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ echo -n &#39;Subject: test\\n\\nTesting ssmtp&#39; | sendmail -v some-recipient@gmail.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="custom-environment-variables" tabindex="-1"><a class="header-anchor" href="#custom-environment-variables" aria-hidden="true">#</a> Custom environment variables</h2><p>You can define your own environment variables for ePortal process.</p><p>There is the <code>/usr/share/kcare-eportal/environment</code> folder, which is basically daemon tools compatible envdir.</p><p>For example, to disable the default https verification you can set the <code>PYTHONHTTPSVERIFY</code> environment variable to <code>0</code> as follows:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># echo 0 &gt; /usr/share/kcare-eportal/environment/PYTHONHTTPSVERIFY\`
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="authentication-using-single-sign-on" tabindex="-1"><a class="header-anchor" href="#authentication-using-single-sign-on" aria-hidden="true">#</a> Authentication using Single Sign On</h2><p>ePortal supports Single Sign On authentication by &quot;OAuth 2.0&quot; standard, &quot;Authorization Code&quot; flow.</p><h3 id="sso-configuration" tabindex="-1"><a class="header-anchor" href="#sso-configuration" aria-hidden="true">#</a> SSO Configuration</h3><p>To enable SSO you need to configure OAuth2 authentication service provider and ePortal.</p><h4 id="okta-application-setup-example" tabindex="-1"><a class="header-anchor" href="#okta-application-setup-example" aria-hidden="true">#</a> Okta Application setup example</h4><p>You set up your OpenID Connect application inside the Okta Admin Console:</p><ol><li><p>In the Admin Console, go to <strong>Applications</strong> &gt; <strong>Applications</strong>.</p></li><li><p>Click <strong>Create App Integration</strong>.</p></li><li><p>On the Create a new app integration page, select <strong>OIDC - OpenID Connect</strong> for the <strong>Sign-in method</strong> and then select <strong>Web Application</strong> as the <strong>Application type</strong>.</p></li><li><p>Fill in the <strong>Application Settings</strong>.</p></li></ol><table><thead><tr><th><strong>Setting</strong></th><th><strong>Value</strong></th></tr></thead><tbody><tr><td>Sign-in redirect URI</td><td>http://eportal_ip/admin/sso/login/callback</td></tr><tr><td>Sign-out redirect URI</td><td>http://eportal_ip/admin/login</td></tr></tbody></table><ol start="5"><li>Obtain <em>Client ID</em>, <em>Client secret</em>, the full URL to the <code>/authorize</code>, <code>/token</code>, <code>/userinfo</code> endpoints.</li></ol><h4 id="eportal-setup" tabindex="-1"><a class="header-anchor" href="#eportal-setup" aria-hidden="true">#</a> ePortal setup</h4><p>On the ePortal machine, configure SSO settings.</p><p>Edit <a href="#config-files">ePortal config file</a>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>OIDC_AUTH_URL=&quot;https://dev-61441893.okta.com/oauth2/v1/authorize&quot;
OIDC_TOKEN_URL=&quot;https://dev-61441893.okta.com/oauth2/v1/token&quot;
OIDC_USERINFO_URL=&quot;https://dev-61441893.okta.com/oauth2/v1/userinfo&quot;
OIDC_LOGOUT_URL=&quot;https://dev-61441893.okta.com/oauth2/v1/logout&quot;

OIDC_CLIENT_ID=&quot;0Aa134lzhUKj8jDMo5d7&quot;
OIDC_CLIENT_SECRET=&quot;AoBNuWRLRu2dxIR3Q0btO53N1entmGxBjQqwmjVL&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Restart ePortal (see the <a href="#stopping-starting">Stopping &amp; Starting</a> section, choose a corresponding OS).</p><p>If all settings configured correctly the new <strong>Sign In with SSO</strong> button has to appear on login page <code>http://eportal_ip/admin/login</code></p><p><img src="`+B+`" alt="sso eportal"></p><h2 id="custom-patchsets-storage" tabindex="-1"><a class="header-anchor" href="#custom-patchsets-storage" aria-hidden="true">#</a> Custom patchsets storage</h2><p>By default patchsets and databases are stored in <code>/var/lib/eportal</code>. You can configure it to use split storage, for example to keep patchsets on external block device.</p><div class="danger custom-block"><p class="custom-block-title">Note</p><p>For ePortal installations prior to version 2.6-1, patchsets and databases were stored in <code>/usr/share/kcare-eportal</code> by default on RHEL-based systems. When upgrading these installations to newer ePortal versions, the original storage location is preserved and continues to be used.</p></div><p>Edit <a href="#config-files">ePortal config file</a>:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>PATCHES_DIR = &#39;/path/to/patchsets/storage&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal sync-nginx-conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>It initializes storage and makes corresponding modifications to nginx config to serve patchsets from a new place.</p><p>And restart <code>nginx</code> and <code>eportal</code> services to apply changes:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># systemctl restart eportal nginx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a> Troubleshooting</h2><p>If you have any questions regarding setting up and operating ePortal, please reach out to the support team. To simplify the analysis of a problem, it is often necessary to provide additional information about the system environment. It is recommended to use the ePortal CLI to collect this information and submit it to support.</p><p>Run:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal doctor
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>In order for the auto-submission to work, you need to configure patch source (see <a href="#patchset-deployment">PatchSet deployment</a>).</p><p>If you experience problems configuring the patch source or have problems accessing the Internet, you can generate a report and submit it manually.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># kc.eportal doctor --no-send
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>The above command will create an archive with the collected data and output the path to it. You can inspect the contents of the archive if necessary and then send it to the support team.</p>`,57))])}const W=o($,[["render",z],["__file","index.html.vue"]]);export{W as default};
